+	}
+	defer func() { _ = rows.Close() }()
+	var out []Group
+	for rows.Next() {
+		var g Group
+		var createdAt int64
+		if err := rows.Scan(&g.JID, &g.Name, &g.OwnerJID, &createdAt); err != nil {
+			return nil, err
+		}
+		g.CreatedAt = fromUnix(createdAt)
